An iterative implementation utilizes a while loop with low <= high condition. The mid index is calculated safely using: mid = low + (high - low) / 2;

Code snippet:
int binarySearch(int arr[], int size, int target) {
    int low = 0, high = size - 1;
    while(low <= high) {
        int mid = low + (high - low)/2;
        if(arr[mid] == target) return mid;
        if(arr[mid] < target) low = mid + 1;
        else high = mid - 1;
    }
    return -1;
}

We can identify cycles in an undirected graph by tracking visited vertices. During DFS traversal, if an adjacent vertex is visited and is not the parent of the current vertex, a cycle is present.

Code snippet:
#include <stdbool.h>
#define V 5
bool isCyclicUtil(int v, bool visited[], int parent, int adj[V][V]) {
    visited[v] = true;
    for (int i = 0; i < V; i++) {
        if (adj[v][i]) {
            if (!visited[i]) {
                if (isCyclicUtil(i, visited, v, adj)) return true;
            } else if (i != parent) {
                return true;
            }
        }
    }
    return false;
}
bool isCyclic(int adj[V][V]) {
    bool visited[V] = {false};
    for (int i = 0; i < V; i++) {
        if (!visited[i]) {
            if (isCyclicUtil(i, visited, -1, adj)) return true;
        }
    }
    return false;
}

