void mergeSorted(int arr1[], int n1, int arr2[], int n2, int dest[]) {
    int i = 0, j = 0, k = 0;
    while (i < n1 && j < n2) {
        if (arr1[i] <= arr2[j]) {
            dest[k++] = arr1[i++];
        } else {
            dest[k++] = arr2[j++];
        }
    }
    while (i < n1) dest[k++] = arr1[i++];
    while (j < n2) dest[k++] = arr2[j++];
}

A recursive DFS uses a boolean tracking array to prevent infinite cycles. When a node is visited, the function prints its identifier and recursively visits all its unvisited adjacent neighbors.

