#include <stdio.h>
#include <stdbool.h>
#define VERTICES 4

void dfsHelper(int vertex, int matrix[VERTICES][VERTICES], bool visited[VERTICES]) {
    visited[vertex] = true;
    printf("%d ", vertex);
    for (int i = 0; i < VERTICES; i++) {
        if (matrix[vertex][i] == 1 && !visited[i]) {
            dfsHelper(i, matrix, visited);
        }
    }
}

void runDFS(int matrix[VERTICES][VERTICES], int startVertex) {
    bool visited[VERTICES] = {false};
    printf("DFS Traversal starting from vertex %d: ", startVertex);
    dfsHelper(startVertex, matrix, visited);
    printf("\n");
}

